<?php $editing = !empty($editUser); ?>
<div class="page-header"><div><h2>User Management</h2><p>Create and manage platform users across Admin, Manager, Agent, and Client portals with team linkage.</p></div></div>
<div class="grid-two">
<div class="card"><h3><?= $editing ? 'Edit User' : 'Add User' ?></h3><form method="post" class="stack-form"><?= csrf_field() ?><input type="hidden" name="action" value="<?= $editing ? 'update' : 'create' ?>"><?php if ($editing): ?><input type="hidden" name="id" value="<?= e((string)$editUser['id']) ?>"><?php endif; ?><input name="full_name" placeholder="Full Name" value="<?= e($editUser['full_name'] ?? '') ?>" required><input name="email" type="email" placeholder="Email" value="<?= e($editUser['email'] ?? '') ?>" required><select name="role"><?php foreach (['admin','manager','agent','client'] as $role): ?><option value="<?= e($role) ?>" <?= (($editUser['role'] ?? 'agent')===$role)?'selected':''; ?>><?= e(ucfirst($role)) ?></option><?php endforeach; ?></select><select name="manager_user_id"><option value="">Manager / Team Lead</option><?php foreach ($managerOptions as $manager): ?><option value="<?= e((string)$manager['id']) ?>" <?= ((string)($editUser['manager_user_id'] ?? '') === (string)$manager['id']) ? 'selected' : '' ?>><?= e($manager['full_name']) ?></option><?php endforeach; ?></select><select name="portal_client_id"><option value="">Linked Client (for client users)</option><?php foreach ($clientOptions as $client): ?><option value="<?= e((string)$client['id']) ?>" <?= ((string)($editUser['portal_client_id'] ?? '') === (string)$client['id']) ? 'selected' : '' ?>><?= e($client['company_name']) ?> · <?= e($client['contact_name']) ?></option><?php endforeach; ?></select><select name="is_active"><?php foreach ([1=>'Active',0=>'Inactive'] as $v=>$label): ?><option value="<?= e((string)$v) ?>" <?= ((string)($editUser['is_active'] ?? '1')===(string)$v)?'selected':''; ?>><?= e($label) ?></option><?php endforeach; ?></select><input type="password" name="password" placeholder="<?= $editing ? 'New Password (optional)' : 'Password' ?>" <?= $editing ? '' : 'required' ?>><div class="actions"><button type="submit"><?= $editing ? 'Save Changes' : 'Create User' ?></button><?php if ($editing): ?><a class="btn-muted" href="index.php?page=users">Cancel</a><?php endif; ?></div></form></div>
<div class="card"><h3>Users</h3><table><thead><tr><th>Name</th><th>Role</th><th>Manager</th><th>Portal Link</th><th>Status</th><th></th></tr></thead><tbody><?php foreach ($users as $row): ?><tr><td><?= e($row['full_name']) ?><div class="muted"><?= e($row['email']) ?></div></td><td><span class="tag"><?= e($row['role']) ?></span></td><td><?= e((string)($row['manager_user_id'] ?? '')) ?></td><td><?= e((string)($row['portal_client_id'] ?? '')) ?></td><td><?= !empty($row['is_active']) ? 'Active' : 'Inactive' ?></td><td class="table-actions"><a href="index.php?page=users&id=<?= e((string)$row['id']) ?>">Edit</a><?php if (App\Core\Auth::can('users','delete')): ?><form method="post" onsubmit="return confirm('Delete this user?');"><?= csrf_field() ?><input type="hidden" name="action" value="delete"><input type="hidden" name="id" value="<?= e((string)$row['id']) ?>"><button class="btn-danger" type="submit">Delete</button></form><?php endif; ?></td></tr><?php endforeach; ?></tbody></table></div>
</div>
